oViewed/25/public_identifier": "martin-röstel-372664106", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAABrLKwYBON4ooG8LlJmh_93iOfdX-tjGAn4", "profilePic": "https://media.licdn.com/dms/image/v2/C4D03AQGCRGP2O9iNhw/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1617514164671?e=1778112000&v=beta&t=6VvDel114iJLWvyjEEiVXyCl4tsY1Khhon7XtNBt3HE", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/C4D03AQGCRGP2O9iNhw/profile-displayphoto-shrink_400_400/profile-displayphoto-shrink_400_400/0/1617514164671?e=1778112000&v=beta&t=6VvDel114iJLWvyjEEiVXyCl4tsY1Khhon7XtNBt3HE", "publicIdentifier": "mwetzlar", "recommendations/0/context": "Michael reported directly to Martin", "recommendations/0/date": "May 2, 2021", "recommendations/0/description": "I had the pleasure of working with Martin, as a Captain on several occasions including Trans-Atlantic Cruises. I truly enjoyed being in his team, as he is not only a very good, professional and respected captain among the crew, he also has become a popular and very approachable host for our guests. Everybody feels in good hands with him. He is an excellent leader with very good communication skills, who always puts safety first. His decisions are based on facts and figures and his commands are clear and understood by everyone. I hope that one day we have a chance to cruise together again.", "recommendations/0/name": "Martin Rittig", "recommendations/0/subtitle": "Marine Pilot/ Cruise Ship Captain", "recommendations/0/url": "https://www.linkedin.com/in/martin-rittig-captain/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAADVo168BLDioh7NNC44rJqmcHvMH18Q6f0g", "recommendations/1/context": "Michael managed Sarah directly", "recommendations/1/date": "December 7, 2020", "recommendations/1/description": "I had the pleasure of working with Sarah on several occasions. The first time when she was a port operations manager, where she was very organized and managed port authorities, ships agents and transport logistics in a superior way. Her willingness to exceed expectations in general is unpaired. It was clear to me after a very short time, that I wanted Sarah to be in my team and her following promotions to Secon d purser and now chief purser were no surprise. She is definitely an asset to the company. I look forward to working with Sarah on many future occasions.  ", "recommendations/1/name": "Sarah Krabbe", "recommendations/1/subtitle": "Specialist Guest Service Operations", "recommendations/1/url": "https://www.linkedin.com/in/sarah-krabbe-a265aa6b/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAA7cHz4B1eotDX5hdlVdT964lKwnrIIwyjM", "recommendations/2/context": "Michael managed Jarek directly", "recommendations/2/date": "September 25, 2020", "recommendations/2/description": "I head the pleasure of working with Jarek on AIDA Prima, where we had to manage some of the toughest situations due to external events. At all times I could count on Jarek and thanks to his good professional knowledge, guests and crew were always satisfied. I can fully recommend him to be in charge of big operations.", "recommendations/2/name": "Jarek Belling", "recommendations/2/subtitle": "Group Managing Director/ Geschäftsführer", "recommendations/2/url": "https://www.linkedin.com/in/jarek-belling-b3a651106/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAABrKyh4BDWOmGv0rcagMfxMxnCWpNdtD5JQ", "recommendations/3/context": "Michael managed Jan-Philipp directly", "recommendations/3/date": "September 25, 2020", "recommendations/3/description": "Jan-Philip is a person that has this great out of the box management style, which makes him very creative and stand apart from other hotel managers. His promotion was to become a General Manager was well deserved and I am sure he will go far in life.", "recommendations/3/name": "Jan-Philipp Schmid", "recommendations/3/subtitle": "Global Cruise Industry Leader | Driving Operational Efficiency & Hygiene Excellence at Scale | Ex-Hotel Director (700+ Crew)", "recommendations/3/url": "https://www.linkedin.com/in/janphilippschmid/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAABERArgBIs359fVPcPK9VJfg_QkA-qCed8g", "recommendations/4/context": "Michael managed Roman Ray directly", "recommendations/4/date": "September 1, 2019", "recommendations/4/description": "Roman is a doer, am achiever and someone who goes for gold. I had the pleasure working with him during the Disney Paris Opening, where he was still a management trainee. It was clear to me from the moment I met him that he will do great. His enthusiasm, his refined skills in people management, his creativity and last but not least his endless energy make him a tremendous leader. Don't loose out to get this guy. ", "recommendations/4/name": "Roman Ray Straub", "recommendations/4/subtitle": "General Manager with a background in hospitality management and resort operations.", "recommendations/4/url": "https://www.linkedin.com/in/roman-ray-straub-305b4a1/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAABY3TUB9uXN-KfNJNUFJl7rGUpWSuaCX9Q", "recommendations/5/context": "Michael was Siegfried's client", "recommendations/5/date": "May 6, 2014", "recommendations/5/description": "Siegfried was the our General Manager in Hoi An, Vietnam, where in a short time after his start, he was able to turn around an operation in very difficult circumstances. He was highly respected by the entire team and the owners, who were at times very difficult to please. I would recommend Siegfried to any international 4 and 5 hotel group.", "recommendations/5/name": "Siegfried Steindl (MBA)", "recommendations/5/subtitle": "General Manager at Hotel Equatorial Ho Chi Minh City", "recommendations/5/url": "https://www.linkedin.com/in/siegfried-steindl/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAEnqh0B6T1SPFWMgjx0H-8c8QPF0suWits", "recommendations/6/context": "Michael was Mauro's client", "recommendations/6/date": "May 26, 2012", "recommendations/6/description": "I have worked with Mauro on several Hotel projects in Vietnam and can only say that he is very knowledgeable within the Vietnamese Hotel development market and a real advisor for the right project to take on that will produce the desired results. I would work with Mauro any time again on a hospitality projects in Vietnam.", "recommendations/6/name": "Mauro Gasparotti", "recommendations/6/subtitle": "Founder at WeHub, and Senior Director at Savills Hotels Asia Pacific", "recommendations/6/url": "https://www.linkedin.com/in/mauro-gasparotti-93043914/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAALpZPQBUKT2jo7ldnnHZihhmJ7Sig1cRkg", "recommendations/7/context": "Michael was Kevin's client", "recommendations/7/date": "March 24, 2009", "recommendations/7/description": "Kevin is a very knowledgable and detailed manager, who achieves top results. I appreciated most his out of the box approach.", "recommendations/7/name": "Kevin So (蘇廣平)", "recommendations/7/subtitle": "Managing Director at Cornerstone Investment Consulting （Real Estate)", "recommendations/7/url": "https://www.linkedin.com/in/kevinso/", "recommendations/7/urn": "urn:li:fsd_profile:ACoAAACAaHgBU-AslCJHbbJpeabFr9XRGaRiSr8", "recommendations/8/context": "Michael managed Roman directly", "recommendations/8/date": "August 12, 2008", "recommendations/8/description": "Roman has been working directly under me during the opening period of Disney Resort Paris. I like to recommend him for his exceptional people skills and refined approach to the hospitality business. He has become a great respected leader, who can manage any challenge.", "recommendations/8/name": "Roman Straub", "recommendations/8/subtitle": "general manager at palenca luxury hotels", "recommendations/8/url": "https://www.linkedin.com/in/roman-straub-9596846/", "recommendations/8/urn": "urn:li:fsd_profile:ACoAAAEq0FUBU7f7k3wxKs2elbgy99HCTD106BU", "recommendations/9/context": "Michael worked with Nk on the same team", "recommendations/9/date": "July 26, 2008", "recommendations/9/description": "It is my pleasure to recommend and NK as a wise prudent and result driven leader. During the time we spent together, I would not have gone anywhere without his excellent advise. I have seen him always as a manager leading by examples and setting the highest standards for himself and the service level in the organization he has been involved.", "recommendations/9/name": "Nk Akers", "recommendations/9/subtitle": "Hospitality Consultant at Self-Employed", "recommendations/9/url": "https://www.linkedin.com/in/nk-akers-ba79098/", "recommendations/9/urn": "urn:li:fsd_profile:ACoAAAGO728BbyykGDkOKNCsu01DG0aoIRVJ4hA", "recommendations/10/context": "Michael was senior to Beat but didn't manage Beat directly", "recommendations/10/date": "July 25, 2008", "recommendations/10/description": "I recommend Beat as a wise and straigh forward business man who has what it takes to produce top results in the today's highly competitive international hotel world.", "recommendations/10/name": "Beat Wiesmann", "recommendations/10/subtitle": "General Manager at Kempinski Hotels", "recommendations/10/url": "https://www.linkedin.com/in/beat-wiesmann-3428224/", "recommendations/10/urn": "urn:li:fsd_profile:ACoAAADVUWIBwmgQJx0uCHDSNirK_qMV4rNbbEQ", "recommendationsReceived/0/context": "Sarah reported directly to Michael", "recommendationsReceived/0/date": "December 13, 2020", "recommendationsReceived/0/description": "I have had the opportunity to work with Michael on several occasions in the past few years on board the AIDA vessels. During this time he was my colleague, later on also my manager and in some occasions even a mentor. \nHe is very aware of employee's competencies and is able to trigger them to get the best of them, even if they think they would not be capable of the same. \n\nDuring challenging situations, he had a very professional attitude & kept a clear mind, while giving competent advice to me and the team, creating a trustful & reliable working environment. \n\nHe is very knowledgable in the field of hotel operation, management and development of new ideas. \n\nWhat really impressed me the most was, the way that he knows how to convince others of his ideas, that can seem unconventional at times, but will lead to a successful outcome in the end and eventually a unique experience for the guests, by being enthuiastic and self confident about them.  \n\nI am looking forward to working with Michael in the future, as he is a colleague that I would recommend without any hesitation and would be a real asset for any team he is working with.", "recommendationsReceived/0/name": "Sarah Krabbe", "recommendationsReceived/0/subtitle": "Specialist Guest Service Operations", "recommendationsReceived/0/url": "https://www.linkedin.com/in/sarah-krabbe-a265aa6b/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAA7cHz4B1eotDX5hdlVdT964lKwnrIIwyjM", "recommendationsReceived/1/context": "Kevin worked with Michael but they were at different companies", "recommendationsReceived/1/date": "March 25, 2009", "recommendationsReceived/1/description": "Michael is very knowledgeable about the hospitality industry and has vast Asia experiences ranging from Indonesia, Thailand, Hong Kong and mainland China.  He is very talented and a pleasure to work with.", "recommendationsReceived/1/name": "Kevin So (蘇廣平)", "recommendationsReceived/1/subtitle": "Managing Director at Cornerstone Investment Consulting （Real Estate)", "recommendationsReceived/1/url": "https://www.linkedin.com/in/kevinso/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAACAaHgBU-AslCJHbbJpeabFr9XRGaRiSr8", "recommendationsReceived/2/context": "Andreas worked with Michael on the same team", "recommendationsReceived/2/date": "November 1, 2008", "recommendationsReceived/2/description": "I have worked together with Michael at the Royal Abjar Dubai and again when he became owner of Cyrus Hotels and Resorts. He is a thorough professional in all aspects of hotel managment and hotel development and has always achieved or surpassed high targets. He is also good at controlling budgets and is a good leader and motivator for his staff and colleagues. I am sure Michael can contribute in many ways to the success of small, medium or large companies.", "recommendationsReceived/2/name": "Andreas Moser", "recommendationsReceived/2/subtitle": "Retired", "recommendationsReceived/2/url": "https://www.linkedin.com/in/andreasmoser/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAADU1c0BIchLldNbRWbihf9-q99B4K2iOcg", "recommendationsReceived/3/context": "Beat worked with Michael on the same team", "recommendationsReceived/3/date": "September 25, 2008", "recommendationsReceived/3/description": "I know Michael to be a smart hotel professional with a clear and bright vision who can make things happen to achieve bottom line goals.", "recommendationsReceived/3/name": "Beat Wiesmann", "recommendationsReceived/3/subtitle": "General Manager at Kempinski Hotels", "recommendationsReceived/3/url": "https://www.linkedin.com/in/beat-wiesmann-3428224/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAADVUWIBwmgQJx0uCHDSNirK_qMV4rNbbEQ", "recommendationsReceived/4/context": "Roman reported directly to Michael", "recommendationsReceived/4/date": "August 24, 2008", "recommendationsReceived/4/description": "michael is a great hard working goal oriented manager", "recommendationsReceived/4/name": "Roman Straub", "recommendationsReceived/4/subtitle": "general manager at palenca luxury hotels", "recommendationsReceived/4/url": "https://www.linkedin.com/in/roman-straub-9596846/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAEq0FUBU7f7k3wxKs2elbgy99HCTD106BU", "recommendationsReceived/5/context": "Nk was senior to Michael but didn't manage Michael directly", "recommendationsReceived/5/date": "July 26, 2008", "recommendationsReceived/5/description": "Michael stood out as a strong qualified professional with a uniqu